//NS, DLT ,13/03/2025 System should not allow to book "Future Date" transactions & also should pick from "As on Date" inventory.
/// <summary>
/// System should not allow to book "Future Date" transactions & also should pick from "As on Date" inventory.
/// </summary>
/// <param name = "_itemId">_itemId</param>
/// <param name = "_transDate">_transDate</param>
/// <returns>ret</returns>
static public boolean checkItemPostingDate(
    ItemId          _itemId,
    TransDate       _transDate)
{
    boolean ret = next checkItemPostingDate(_itemId, _transDate);

    if(ETGACFParameters::find().EnableUATSmallPoints == NoYes::Yes)
    {
        TransDate currentdate = DateTimeUtil::getSystemDate(DateTimeUtil::getUserPreferredTimeZone());

        if(_transDate > currentdate)
        {
            throw error(strFmt("Posting date %1 can not be greater than today's date", _transDate));
        }
    }

    return ret;
}

//NE, DLT ,13/03/2025 System should not allow to book "Future Date" transactions & also should pick from "As on Date" inventory.
